#include <stdio.h>

/* http://codeforces.com/contest/894/submission/34556698 (Dukkha) */

#define MD	1000000007

int power(int a, int b) {
	int p;

	if (b == 0)
		return 1;
	p = power(a, b / 2);
	p = (long long) p * p % MD;
	if (b % 2 == 1)
		p = (long long) p * a % MD;
	return p;
}

int main() {
	long long n, m, k;

	scanf("%lld%lld%lld", &n, &m, &k);
	printf("%d\n", k == -1 && n % 2 != m % 2 ? 0 : power(2, (long long) ((n - 1) % (MD - 1)) * ((m - 1) % (MD - 1)) % (MD - 1)));
	return 0;
}

