use std::io;
use std::str::FromStr;

use std::io::prelude::*;
use std::io::BufReader;
use std::cmp::{max, min};

fn get_line() -> String {
    let mut input = String::new();
    io::stdin().read_line(&mut input).unwrap();
    input
}

fn get_vec<T>() -> Vec<T>
where T: FromStr,
      <T as FromStr>::Err: std::fmt::Debug,
{
    get_line().split_whitespace().map(|k| k.parse().unwrap()).collect()
}

const p: i64 = 1_000_000_007;

fn main() {
    let (n, m, k) = {
        let input = get_line();
        let mut it = input.split_whitespace().map(|x| x.parse::<i64>().unwrap());
        (
            it.next().unwrap(),
            it.next().unwrap(),
            it.next().unwrap(),
            )
    };

    // (2^{n - 1})^{m - 1}
    // 2^{n + m - 2}

    if k == -1 && (n + m) % 2 != 0 {
        println!("0");
        return;
    }

    let n0 = {
        let p0 = p - 1;
        ((n - 1) % p0) * ((m - 1) % p0) % p0
    };

    let mut two_pow_two_pow = Vec::new();

    let mul = |a, b| {
        ((a % p) * (b % p)) % p
    };

    let mut i = 2;
    for _ in 0..40 {
        two_pow_two_pow.push(i);
        i = mul(i, i);
    }

    let mut ans = 1;

    for i in 0..40 {
        if n0 & (1 << i) != 0 {
            ans = mul(ans, two_pow_two_pow[i]);
        }
    }

    println!("{}", ans);
}
